import { normalizeStickers } from './stickerCatalog';

/** Convert Neo4j driver types to plain JSON-safe values. */
export function toPlainValue(val) {
  if (val == null) return val;
  if (typeof val === 'object' && typeof val.toNumber === 'function') {
    return val.toNumber();
  }
  if (Array.isArray(val)) {
    return val.map(toPlainValue);
  }
  return val;
}

function safeGet(record, key) {
  return record.has(key) ? record.get(key) : null;
}

export function buildNode(name, record, prefix) {
  const affiliationKey = `${prefix}Affiliation`;
  const roleKey = `${prefix}Role`;
  const emailKey = `${prefix}Email`;
  const websiteKey = `${prefix}Website`;
  const locationKey = `${prefix}Location`;
  const stickersKey = `${prefix}Stickers`;

  return {
    name,
    affiliation: safeGet(record, affiliationKey) || safeGet(record, roleKey) || '',
    role: safeGet(record, affiliationKey) || safeGet(record, roleKey) || '',
    location: safeGet(record, locationKey) || '',
    email: safeGet(record, emailKey) || safeGet(record, websiteKey) || '',
    website: safeGet(record, emailKey) || safeGet(record, websiteKey) || '',
    stickers: normalizeStickers(safeGet(record, stickersKey)),
    x: Math.random() * 500,
    y: Math.random() * 500,
  };
}

export function buildLink(source, target, record) {
  const link = { source, target };
  if (record) {
    if (record.has('linkNote')) link.note = record.get('linkNote') || '';
    if (record.has('linkContext')) link.context = record.get('linkContext') || '';
    if (record.has('linkImpact')) {
      const impact = record.get('linkImpact');
      link.impact = impact != null ? toPlainValue(impact) : null;
    }
    if (record.has('linkCreatedAt')) {
      link.createdAt = toPlainValue(record.get('linkCreatedAt'));
    }
  }
  return link;
}

export function parseGraphRecords(records) {
  const nodesMap = new Map();
  const links = [];

  records.forEach((record) => {
    if (
      record.has('source') &&
      record.has('target') &&
      record.get('source') &&
      record.get('target') &&
      typeof record.get('source') === 'string' &&
      typeof record.get('target') === 'string'
    ) {
      const source = record.get('source');
      const target = record.get('target');

      if (!nodesMap.has(source)) {
        nodesMap.set(source, buildNode(source, record, 'source'));
      }
      if (!nodesMap.has(target)) {
        nodesMap.set(target, buildNode(target, record, 'target'));
      }
      if (nodesMap.has(source) && nodesMap.has(target)) {
        links.push(buildLink(source, target, record));
      }
    } else if (record.has('source') && record.get('source')) {
      const source = record.get('source');
      const target = record.has('target') ? record.get('target') : null;

      if (!nodesMap.has(source)) {
        nodesMap.set(source, buildNode(source, record, 'source'));
      }
      if (target && !nodesMap.has(target)) {
        nodesMap.set(target, buildNode(target, record, 'target'));
      }
      if (target) {
        links.push(buildLink(source, target, record));
      }
    } else {
      record.keys.forEach((key) => {
        const node = record.get(key);
        if (node && node.properties && node.identity) {
          const name = node.properties.name || `Node-${node.identity.low}`;
          if (!nodesMap.has(name)) {
            nodesMap.set(name, {
              name,
              affiliation: node.properties.affiliation || node.properties.role || '',
              role: node.properties.affiliation || node.properties.role || '',
              location: node.properties.location || '',
              email: node.properties.email || node.properties.website || '',
              website: node.properties.email || node.properties.website || '',
              stickers: normalizeStickers(node.properties.stickers),
              x: Math.random() * 500,
              y: Math.random() * 500,
            });
          }
        }
      });
    }
  });

  return { nodes: Array.from(nodesMap.values()), links };
}

/** Ensure graph data is safe for React state and localStorage. */
export function sanitizeGraphData(data) {
  const nodes = (data.nodes || []).map((n) => ({
    name: n.name,
    affiliation: n.affiliation || n.role || '',
    role: n.role || n.affiliation || '',
    location: n.location || '',
    email: n.email || n.website || '',
    website: n.website || n.email || '',
    stickers: normalizeStickers(n.stickers),
    x: typeof n.x === 'number' ? n.x : Math.random() * 500,
    y: typeof n.y === 'number' ? n.y : Math.random() * 500,
  }));

  const links = (data.links || []).map((l) => ({
    source: typeof l.source === 'object' ? l.source.name : l.source,
    target: typeof l.target === 'object' ? l.target.name : l.target,
    note: l.note || '',
    context: l.context || '',
    impact: l.impact != null ? toPlainValue(l.impact) : null,
    createdAt: l.createdAt != null ? toPlainValue(l.createdAt) : null,
  }));

  return { nodes, links };
}
